const sharp = require\('sharp'\);
const path = require\('path'\);

const src = 'C:/Users/chad/Downloads/dispatch_logo.png';
const iconsDir = 'client/public/icons';

async function run\(\) {
  // The logo is 2816x1536 \(landscape\). We need square icons.
  // Strategy: resize to fit within a square, centering with padding.
  // Use transparent background since the logo has a white/light bg.

  // First, let's extract with a transparent/dark background to match the app theme
  const sizes = [
    { file: 'icon-192x192.png', size: 192, padding: 16 },
    { file: 'icon-512x512.png', size: 512, padding: 40 },
    { file: 'icon-maskable-512x512.png', size: 512, padding: 80 }, // more padding for maskable safe zone
  ];

  for \(const { file, size, padding } of sizes\) {
    const innerSize = size - padding * 2;
    await sharp\(src\)
      .resize\(innerSize, innerSize, { fit: 'contain', background: { r: 0, g: 0, b: 0, alpha: 0 } }\)
      .extend\({
        top: padding,
        bottom: padding,
        left: padding,
        right: padding,
        background: { r: 0, g: 0, b: 0, alpha: 0 },
      }\)
      .png\(\)
      .toFile\(path.join\(iconsDir, file\)\);
    console.log\('Created ' + file + ' \(' + size + 'x' + size + '\)'\);
  }

  // Also create a favicon \(32x32 PNG, then we can use it as ico\)
  // Actually let's create a 64x64 PNG and a proper .ico
  await sharp\(src\)
    .resize\(64, 64, { fit: 'contain', background: { r: 0, g: 0, b: 0, alpha: 0 } }\)
    .png\(\)
    .toFile\('client/public/favicon.png'\);
  console.log\('Created favicon.png \(64x64\)'\);

  // Create 32x32 and 16x16 for ICO
  const buf32 = await sharp\(src\)
    .resize\(32, 32, { fit: 'contain', background: { r: 0, g: 0, b: 0, alpha: 0 } }\)
    .png\(\)
    .toBuffer\(\);

  const buf16 = await sharp\(src\)
    .resize\(16, 16, { fit: 'contain', background: { r: 0, g: 0, b: 0, alpha: 0 } }\)
    .png\(\)
    .toBuffer\(\);

  // Build ICO file \(contains 16x16 and 32x32 PNG entries\)
  function buildIco\(pngBuffers\) {
    const numImages = pngBuffers.length;
    const headerSize = 6;
    const dirEntrySize = 16;
    const dirSize = dirEntrySize * numImages;
    let offset = headerSize + dirSize;

    const entries = [];
    for \(const png of pngBuffers\) {
      entries.push\({ offset, size: png.length }\);
      offset += png.length;
    }

    const header = Buffer.alloc\(headerSize\);
    header.writeUInt16LE\(0, 0\); // reserved
    header.writeUInt16LE\(1, 2\); // ICO type
    header.writeUInt16LE\(numImages, 4\);

    const dims = [16, 32];
    const dirBufs = entries.map\(\(e, i\) => {
      const buf = Buffer.alloc\(dirEntrySize\);
      buf.writeUInt8\(dims[i], 0\); // width
      buf.writeUInt8\(dims[i], 1\); // height
      buf.writeUInt8\(0, 2\); // color palette
      buf.writeUInt8\(0, 3\); // reserved
      buf.writeUInt16LE\(1, 4\); // color planes
      buf.writeUInt16LE\(32, 6\); // bits per pixel
      buf.writeUInt32LE\(e.size, 8\); // image data size
      buf.writeUInt32LE\(e.offset, 12\); // offset
      return buf;
    }\);

    return Buffer.concat\([header, ...dirBufs, ...pngBuffers]\);
  }

  const ico = buildIco\([buf16, buf32]\);
  require\('fs'\).writeFileSync\('client/public/favicon.ico', ico\);
  console.log\('Created favicon.ico \(16x16 + 32x32\)'\);
}

run\(\).catch\(e => { console.error\(e\); process.exit\(1\); }\);
